import type { PostItem } from '@kyokuya/react-layout-post'
import Link from '@kyokuya/react-link'
import { MarkdownProvider } from '@kyokuya/react-markdown'
import { ArrowRightAltOutlined } from '@material-ui/icons'
import type {
  Definition,
  EcmaImport,
  FootnoteDefinition,
  Root,
} from '@yozora/ast'
import cn from 'clsx'
import React, { useMemo } from 'react'
import Seo from '@/component/seo'
import Toc from '@/component/toc'
import type { TocItemData } from '@/component/toc'
import useActivatedIdentifier from '@/core/hook/useActivatedIdentifier'
import { resolveIdentifier } from '@/core/util/url'
import { Layout } from '../component/Layout'
import { Pagination } from '../component/Pagination'
import { PostContent } from '../component/PostContent'
import { PostLayoutContextProvider } from '../context/Provider'

export interface PostListPageQueryContext {
  /**
   * Current page number.
   */
  current: number
  /**
   * Count of total pages.
   */
  totalPage: number
  /**
   * Url prefix of post pagination page.
   */
  urlPrefix: string
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
}

export interface PostListPageProps extends PostListPageQueryContext {
  posts?: Array<{
    title?: string
    description?: string
    createAt: string
    updateAt: string
    timeToRead: string
    categories: string[]
    tags: string[]
    ecmaImports: EcmaImport[]
    definitionMap: Record<string, Definition>
    footnoteDefinitionMap: Record<string, FootnoteDefinition>
    excerptAst: Root
    fields?: {
      slug?: string
    }
  }> | null
  postItems?: PostItem[] | null
}

export function PostListPage(props: PostListPageProps): React.ReactElement {
  const {
    current,
    totalPage,
    urlPrefix,
    paginationUrl,
    posts: initialPosts,
    postItems: initialPostItems,
  } = props

  const resolveUrl = useMemo<(pageNo: number) => string | null>(() => {
    const prefix = (urlPrefix + '/').replace(/[/]+/g, '/')
    return (pageNo: number): string | null => {
      if (pageNo <= 0 || pageNo > totalPage) return null
      return prefix + '' + pageNo
    }
  }, [urlPrefix, totalPage])

  const {
    activatedIdentifier,
    refreshActivatedIdentifier,
    pauseWatchingScroll,
  } = useActivatedIdentifier('kyokuya-post-list__post', 0)

  const { postItems, tocNodes, articles, description } = (() => {
    const tocNodes: TocItemData[] = []
    const articles: React.ReactElement[] = []
    const posts = initialPosts ?? []
    const postItems = initialPostItems as PostItem[]
    const descriptions: string[] = []

    for (const post of posts) {
      const {
        title,
        createAt,
        timeToRead,
        excerptAst,
        ecmaImports,
        definitionMap,
        footnoteDefinitionMap,
        tags,
      } = post
      const slug: string = post.fields!.slug ?? ''

      const tocItem: TocItemData = {
        depth: 1,
        identifier: 'post-' + resolveIdentifier(title ?? slug),
        title,
      }

      const article: React.ReactElement = (
        <MarkdownProvider
          key={tocItem.identifier}
          ecmaImports={ecmaImports}
          definitionMap={definitionMap}
          footnoteDefinitionMap={footnoteDefinitionMap}
        >
          <div id={tocItem.identifier} className="kyokuya-post-list__post">
            <PostContent
              title={title!}
              createAt={createAt!}
              timeToRead={timeToRead!}
              tags={tags! as any}
              ast={excerptAst}
              slug={slug}
              shouldRenderFooter={false}
            />
            <Link
              url={slug}
              title={title!}
              itemProp="url"
              className="kyokuya-post-list__read-more"
            >
              <span itemProp="headline" aria-label={title!}>
                阅读全文
              </span>
              <ArrowRightAltOutlined />
            </Link>
          </div>
        </MarkdownProvider>
      )

      if (title != null) descriptions.push(title)
      tocNodes.push(tocItem)
      articles.push(article)
    }
    return {
      postItems,
      tocNodes,
      articles,
      description: descriptions.join('\n\n'),
    }
  })()

  return (
    <PostLayoutContextProvider posts={postItems}>
      <Layout
        onScroll={refreshActivatedIdentifier}
        paginationUrl={paginationUrl}
        head={<Seo title={'博文列表-' + current} description={description} />}
        content={
          <div className="kyokuya-post-list">
            {articles}
            <div
              className={cn(
                'kyokuya-post-list__pagination',
                'kyokuya-post__frosted-glass-panel',
              )}
            >
              <Pagination
                totalPage={totalPage}
                current={current}
                resolveUrl={resolveUrl}
              />
            </div>
          </div>
        }
        nav={
          <Toc
            activatedIdentifier={activatedIdentifier}
            nodes={tocNodes}
            pauseWatchingScroll={pauseWatchingScroll}
          />
        }
      />
    </PostLayoutContextProvider>
  )
}

PostListPage.displayName = 'KyokuyaLayoutPostPostListPage'
export default PostListPage
