import type { MagicPanelContentType, PostItem } from './types'

/**
 * Data type provided by PostLayoutContext.
 */
export interface PostLayoutContextData {
  /**
   * All of post tags.
   */
  tags: ReadonlyArray<string>
  /**
   * All of post items.
   */
  posts: ReadonlyArray<PostItem>
  /**
   * Keyword in the searching panel.
   */
  searchingKeyword: string
  /**
   * Whether to display the magic-panel.
   */
  magicPanelVisible: boolean
  /**
   * Which magic-panel should be displayed.
   */
  magicPanelActivated: MagicPanelContentType
}

export const initialPostLayoutContextData: PostLayoutContextData = {
  tags: [],
  posts: [],
  searchingKeyword: '',
  magicPanelVisible: false,
  magicPanelActivated: 'navigation',
}
