import type React from 'react'

type GThis = typeof globalThis & {
  mozRequestAnimationFrame: typeof globalThis.requestAnimationFrame
  msRequestAnimationFrame: typeof globalThis.requestAnimationFrame
  oRequestAnimationFrame: typeof globalThis.requestAnimationFrame
  mozCancelAnimationFrame: typeof globalThis.cancelAnimationFrame
  msCancelAnimationFrame: typeof globalThis.cancelAnimationFrame
  oCancelAnimationFrame: typeof globalThis.cancelAnimationFrame
}

const gThis: GThis = (globalThis ?? window ?? {}) as any

export type Animation = () => void

/**
 * 2d point.
 */
export interface Point2D {
  /**
   * Point x-coordinate
   */
  x: number
  /**
   * Point y-coordinate
   */
  y: number
  /**
   * Velocity in the x direction
   */
  vx: number
  /**
   * Velocity in the y direction
   */
  vy: number
}

/**
 * Request an animation frame.
 */
export const requestAnimationFrame =
  gThis.requestAnimationFrame ??
  gThis.webkitRequestAnimationFrame ??
  gThis.mozRequestAnimationFrame ??
  gThis.msRequestAnimationFrame ??
  gThis.oRequestAnimationFrame ??
  function (animation: Animation): number {
    return window.setTimeout(animation, 1000 / 60)
  }

/**
 * Cancel an animation frame.
 */
export const cancelAnimationFrame =
  gThis.cancelAnimationFrame ??
  gThis.webkitCancelAnimationFrame ??
  gThis.mozCancelAnimationFrame ??
  gThis.msCancelAnimationFrame ??
  gThis.oCancelAnimationFrame ??
  gThis.clearTimeout

/**
 * Create a canvas as the background of the given html element.
 * @param parent
 */
export function createBackgroundCanvas(
  parent: HTMLElement,
  canvasStyle: React.CSSProperties = {},
): HTMLCanvasElement {
  // Make sure the given dom node is not in static position.
  if (getComputedStyle(parent).position === 'static') {
    // eslint-disable-next-line no-param-reassign
    parent.style.position = 'relative'
  }

  const canvas = document.createElement('canvas')
  canvas.width = parent.clientWidth
  canvas.height = parent.clientHeight
  Object.assign(canvas.style, {
    display: 'block',
    position: 'absolute',
    top: 0,
    left: 0,
    width: '100%',
    height: '100%',
    overflow: 'hidden',
    'pointer-events': 'none',
    opacity: 0.5,
    ...canvasStyle,
  })

  parent.prepend(canvas)
  return canvas
}
